# 项目实战-人事系统

在本节中，我们将通过一个综合项目来实践 Java 的核心概念，构建一个简单的人事管理系统。该项目将结合面向对象编程（OOP）、集合、文件操作、异常处理等知识点，帮助你巩固所学知识并提升实际开发能力。

---

## 1. 项目目标

实现一个简单的人事管理系统，支持以下功能：

- 添加员工信息
- 删除员工信息
- 修改员工信息
- 查询员工信息
- 显示所有员工信息
- 保存和加载员工数据到文件

---

## 2. 设计思路

### 2.1 类图设计

```
Employee (员工类)
├── id
├── name
├── age
├── department
└── salary

HRSystem (人事系统)
├── employees (员工列表)
├── saveToFile()
├── loadFromFile()
└── mainMenu()
```

> **说明**：
- `Employee` 类用于存储员工信息
- `HRSystem` 类用于管理员工信息

---

## 3. 代码实现

### 3.1 Employee 类

```java
public class Employee {
    private int id;
    private String name;
    private int age;
    private String department;
    private double salary;

    public Employee(int id, String name, int age, String department, double salary) {
        this.id = id;
        this.name = name;
        this.age = age;
        this.department = department;
        this.salary = salary;
    }

    // Getters 和 Setters
    public int getId() {
        return id;
    }

    public void setId(int id) {
        this.id = id;
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    public int getAge() {
        return age;
    }

    public void setAge(int age) {
        this.age = age;
    }

    public String getDepartment() {
        return department;
    }

    public void setDepartment(String department) {
        this.department = department;
    }

    public double getSalary() {
        return salary;
    }

    public void setSalary(double salary) {
        this.salary = salary;
    }

    @Override
    public String toString() {
        return "Employee{" +
                "id=" + id +
                ", name='" + name + '\'' +
                ", age=" + age +
                ", department='" + department + '\'' +
                ", salary=" + salary +
                '}';
    }
}
```

---

### 3.2 HRSystem 类

```java
import java.io.*;
import java.util.ArrayList;
import java.util.Scanner;

public class HRSystem {
    private ArrayList<Employee> employees;
    private Scanner scanner;

    public HRSystem() {
        this.employees = new ArrayList<>();
        this.scanner = new Scanner(System.in);
    }

    public void loadFromFile() {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream("employees.dat"))) {
            employees = (ArrayList<Employee>) ois.readObject();
            System.out.println("员工数据加载成功！");
        } catch (IOException | ClassNotFoundException e) {
            System.out.println("文件不存在或加载失败，使用默认数据。");
            employees = new ArrayList<>();
        }
    }

    public void saveToFile() {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream("employees.dat"))) {
            oos.writeObject(employees);
            System.out.println("员工数据保存成功！");
        } catch (IOException e) {
            System.out.println("保存失败：" + e.getMessage());
        }
    }

    public void addEmployee() {
        System.out.print("请输入员工ID：");
        int id = scanner.nextInt();
        scanner.nextLine(); // 消费换行符

        System.out.print("请输入员工姓名：");
        String name = scanner.nextLine();

        System.out.print("请输入员工年龄：");
        int age = scanner.nextInt();
        scanner.nextLine(); // 消费换行符

        System.out.print("请输入员工部门：");
        String department = scanner.nextLine();

        System.out.print("请输入员工薪资：");
        double salary = scanner.nextDouble();

        Employee employee = new Employee(id, name, age, department, salary);
        employees.add(employee);
        System.out.println("员工添加成功！");
    }

    public void deleteEmployee() {
        System.out.print("请输入要删除的员工ID：");
        int id = scanner.nextInt();

        Employee employee = findEmployeeById(id);
        if (employee != null) {
            employees.remove(employee);
            System.out.println("员工删除成功！");
        } else {
            System.out.println("未找到该员工！");
        }
    }

    public void updateEmployee() {
        System.out.print("请输入要修改的员工ID：");
        int id = scanner.nextInt();

        Employee employee = findEmployeeById(id);
        if (employee != null) {
            scanner.nextLine(); // 消费换行符

            System.out.print("请输入新姓名：");
            String name = scanner.nextLine();
            employee.setName(name);

            System.out.print("请输入新年龄：");
            int age = scanner.nextInt();
            employee.setAge(age);
            scanner.nextLine(); // 消费换行符

            System.out.print("请输入新部门：");
            String department = scanner.nextLine();
            employee.setDepartment(department);

            System.out.print("请输入新薪资：");
            double salary = scanner.nextDouble();
            employee.setSalary(salary);

            System.out.println("员工信息修改成功！");
        } else {
            System.out.println("未找到该员工！");
        }
    }

    public void queryEmployee() {
        System.out.print("请输入要查询的员工ID：");
        int id = scanner.nextInt();

        Employee employee = findEmployeeById(id);
        if (employee != null) {
            System.out.println(employee);
        } else {
            System.out.println("未找到该员工！");
        }
    }

    public void displayAllEmployees() {
        if (employees.isEmpty()) {
            System.out.println("暂无员工信息！");
        } else {
            System.out.println("所有员工信息：");
            for (Employee employee : employees) {
                System.out.println(employee);
            }
        }
    }

    private Employee findEmployeeById(int id) {
        for (Employee employee : employees) {
            if (employee.getId() == id) {
                return employee;
            }
        }
        return null;
    }

    public void mainMenu() {
        while (true) {
            System.out.println("\n=== 人事管理系统 ===");
            System.out.println("1. 添加员工");
            System.out.println("2. 删除员工");
            System.out.println("3. 修改员工");
            System.out.println("4. 查询员工");
            System.out.println("5. 显示所有员工");
            System.out.println("6. 保存数据");
            System.out.println("7. 退出系统");
            System.out.print("请选择操作：");

            int choice = scanner.nextInt();
            scanner.nextLine(); // 消费换行符

            switch (choice) {
                case 1:
                    addEmployee();
                    break;
                case 2:
                    deleteEmployee();
                    break;
                case 3:
                    updateEmployee();
                    break;
                case 4:
                    queryEmployee();
                    break;
                case 5:
                    displayAllEmployees();
                    break;
                case 6:
                    saveToFile();
                    break;
                case 7:
                    System.out.println("感谢使用人事管理系统！");
                    return;
                default:
                    System.out.println("无效选择，请重新输入！");
            }
        }
    }

    public static void main(String[] args) {
        HRSystem system = new HRSystem();
        system.loadFromFile();
        system.mainMenu();
    }
}
```

---

